// Device-conformance masks captured from a ZD410-203dpi ZPL preview at
// ^GSN,60,60. Each mask is an 80-by-60, MSB-first monochrome cell. The
// additional horizontal cell space preserves the documented UL/CSA glyph
// overhang while allowing deterministic nearest-dot scaling.
const SYMBOL_BASE64: Readonly<Record<string, string>> = Object.freeze({
  A: "",
  B: "",
  C: "",
  D: "",
  E: "",
});

const alphabet =
  "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
const decoded = new Map<string, Uint8Array>();

export function zebraGraphicSymbolData(code: string): Uint8Array | undefined {
  const normalized = code.toUpperCase();
  const encoded = SYMBOL_BASE64[normalized];
  if (!encoded) return undefined;
  const existing = decoded.get(normalized);
  if (existing) return existing;
  const bytes: number[] = [];
  let value = 0;
  let bits = 0;
  for (const character of encoded.replace(/=+$/, "")) {
    value = (value << 6) | alphabet.indexOf(character);
    bits += 6;
    if (bits >= 8) {
      bits -= 8;
      bytes.push((value >> bits) & 0xff);
    }
  }
  const data = Uint8Array.from(bytes);
  decoded.set(normalized, data);
  return data;
}

export const ZEBRA_GRAPHIC_SYMBOL_WIDTH = 80;
export const ZEBRA_GRAPHIC_SYMBOL_HEIGHT = 60;
export const ZEBRA_GRAPHIC_SYMBOL_BYTES_PER_ROW = 10;
